def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        penalty_factor = 1.0
        if ratio < 0.05:
            base_exp = np.exp(-ratio * 20)
            score += base_exp * 15
            for a in range(1, 15):
                mod = (a * ratio * (capacity % 10 + 1)) % 2
                factor = (a ** 3) / (mod + 1)
                if a % 2 == 0:
                    score += factor * np.sin(ratio * np.pi * a)
                else:
                    score -= factor * np.cos(ratio * np.pi * a * 0.5)
            if int(capacity) % 4 == 0:
                score *= 0.75
            if (capacity + item) % 7 == 0:
                score += 8
        elif 0.05 <= ratio < 0.25:
            accum_prod = 1.0
            for n in range(1, int(capacity) + 5):
                val = ratio + (n / (n+2)) * np.sin(n)
                accum_prod *= val
                if accum_prod > 1e7:
                    accum_prod = np.log1p(accum_prod)
                    break
            score = np.sqrt(abs(accum_prod)) * 2 - ratio * 10
            for x in range(5):
                score += ((ratio * (x+1)**3) % 1.0) * (x + 1.1)**2
            if (int(capacity) % 5 == 0 and int(item*3) % 2 == 0):
                score += 5
            else:
                score -= 3
        elif 0.25 <= ratio <= 0.5:
            for m in range(1, 10):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 1.1)
                score += increment
            leftover = capacity - item
            if leftover < 2:
                score += 20 + leftover * 0.6
            else:
                score -= leftover * 1.1
            if score < -8:
                score = abs(score) * 0.5 + 3
            if (int(capacity) % 9 == 0):
                score *= 1.4
            if score > 25:
                score /= 4
        elif 0.5 < ratio <= 0.75:
            penalty = 0.0
            diff = ratio - 0.5
            for p in range(1, 15):
                penalty += ((diff) ** p) * (p ** 1.7) / (p + 0.8)
                if penalty > 100:
                    penalty = np.sqrt(penalty)
                    break
            score = penalty * 18
            if capacity < item * 1.1:
                score += 22
            if (int(capacity * 6) % 8 == 0) and (int(item * 7) % 13 == 0):
                score -= 9
            if score < 0:
                score = abs(score) * 1.6 - 4
            if score > 180:
                score = 180
        elif 0.75 < ratio <= 1.0:
            super_penalty = 0.0
            delta = ratio - 0.75
            for r in range(1, 18):
                term = ((delta) ** r) * (r ** 3.3) / (r + 0.5)
                if term > 12000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 22
            if capacity < item * 1.2:
                score += 30
            if (int(capacity * 11) % 3 == 0) and (int(item * 15) % 7 == 0):
                score -= 11
            for w in range(1, 8):
                score += ((delta / (w + 0.75)) % 1) * (w * 2.3)
            if score < 0:
                score = abs(score) * 0.9 + 7
            if score > 2200:
                score = 2200
        elif 1.0 < ratio <= 1.3:
            extended_penalty = 0.0
            diff = ratio - 1.0
            for q in range(1, 15):
                extended_penalty += ((diff) ** q) * (q ** 3.2) / (q + 1.1)
            score = extended_penalty * 28
            if capacity < item * 1.5:
                score += 38
            if (int(capacity * 7) % 6 == 0) and (int(item * 10) % 9 == 0):
                score -= 14
            for z in range(1, 9):
                score += ((diff / (z + 0.8)) % 1) * (z * 2.5)
            if score < 0:
                score = abs(score) * 0.8 + 5
            if score > 2600:
                score = 2600
        else:
            ultra_penalty = 0.0
            diff = ratio - 1.3
            for s in range(1, 20):
                term = ((diff) ** s) * (s ** 4)
                if term > 15000:
                    term = np.sqrt(term) * 1.3
                ultra_penalty += term
            score = ultra_penalty * 30
            if capacity < item * 2.5:
                score += 40
            if (int(capacity * 17) % 5 == 0) and (int(item * 23) % 8 == 0):
                score -= 18
            for y in range(3, 10):
                score += ((diff / y) % 1) * (y * 2.7)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 3000:
                score = 3000
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 3:
            score *= 2.7
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for i in range(len(priorities)):
        if i > 0 and i < len(priorities) - 1:
            neighbors_avg = (priorities[i-1] + priorities[i+1]) / 2
            priorities[i] = (priorities[i] + neighbors_avg) / 2.5
    return priorities
